6	/// Randomly shuffles a slice.
7	pub(crate) fn shuffle<T>(v: &mut [T]) {
8	    let len = v.len();
9	    if len <= 1 {
10	        return;
11	    }
12	
13	    std::thread_local! {
14	        static RNG: Cell<Wrapping<u32>> = const { Cell::new(Wrapping(1_406_868_647)) };
15	    }
16	
17	    let _ = RNG.try_with(|rng| {
18	        for i in 1..len {
19	            // This is the 32-bit variant of Xorshift.
20	            //
21	            // Source: https://en.wikipedia.org/wiki/Xorshift
22	            let mut x = rng.get();
23	            x ^= x << 13;
24	            x ^= x >> 17;
25	            x ^= x << 5;
26	            rng.set(x);
27	
28	            let x = x.0;
29	            let n = i + 1;
30	
31	            // This is a fast alternative to `let j = x % n`.
32	            //
33	            // Author: Daniel Lemire
34	            // Source: https://lemire.me/blog/2016/06/27/a-fast-alternative-to-the-modulo-reduction/
35	            let j = ((x as u64).wrapping_mul(n as u64) >> 32) as u32 as usize;
36	
37	            v.swap(i, j);
38	        }
39	    });
40	}
