42	/// Sleeps until the deadline, or forever if the deadline isn't specified.
43	pub(crate) fn sleep_until(deadline: Option<Instant>) {
44	    loop {
45	        match deadline {
46	            None => thread::sleep(Duration::from_secs(1000)),
47	            Some(d) => {
48	                let now = Instant::now();
49	                if now >= d {
50	                    break;
51	                }
52	                thread::sleep(d - now);
53	            }
54	        }
55	    }
56	}
