3	// Based on unstable alloc::alloc::Global.
4	//
5	// Note: unlike alloc::alloc::Global that returns NonNull<[u8]>,
6	// this returns NonNull<u8>.
7	pub(crate) struct Global;
8	#[allow(clippy::unused_self)]
9	impl Global {
10	    #[inline]
11	    #[cfg_attr(miri, track_caller)] // even without panics, this helps for Miri backtraces
12	    fn alloc_impl(&self, layout: Layout, zeroed: bool) -> Option<NonNull<u8>> {
13	        // Layout::dangling is unstable
14	        #[inline]
15	        #[must_use]
16	        fn dangling(layout: Layout) -> NonNull<u8> {
17	            // SAFETY: align is guaranteed to be non-zero
18	            unsafe { NonNull::new_unchecked(without_provenance_mut::<u8>(layout.align())) }
19	        }
20	
21	        match layout.size() {
22	            0 => Some(dangling(layout)),
23	            // SAFETY: `layout` is non-zero in size,
24	            _size => unsafe {
25	                #[allow(clippy::disallowed_methods)] // we are in alloc_helper
26	                let raw_ptr = if zeroed {
27	                    alloc::alloc::alloc_zeroed(layout)
28	                } else {
29	                    alloc::alloc::alloc(layout)
30	                };
31	                NonNull::new(raw_ptr)
32	            },
33	        }
34	    }
35	    #[allow(dead_code)]
36	    #[inline]
37	    #[cfg_attr(miri, track_caller)] // even without panics, this helps for Miri backtraces
38	    pub(crate) fn allocate(self, layout: Layout) -> Option<NonNull<u8>> {
39	        self.alloc_impl(layout, false)
40	    }
41	    #[allow(dead_code)]
42	    #[inline]
43	    #[cfg_attr(miri, track_caller)] // even without panics, this helps for Miri backtraces
44	    pub(crate) fn allocate_zeroed(self, layout: Layout) -> Option<NonNull<u8>> {
45	        self.alloc_impl(layout, true)
46	    }
47	    #[allow(dead_code)]
48	    #[inline]
49	    #[cfg_attr(miri, track_caller)] // even without panics, this helps for Miri backtraces
50	    pub(crate) unsafe fn deallocate(self, ptr: NonNull<u8>, layout: Layout) {
51	        if layout.size() != 0 {
52	            // SAFETY:
53	            // * We have checked that `layout` is non-zero in size.
54	            // * The caller is obligated to provide a layout that "fits", and in this case,
55	            //   "fit" always means a layout that is equal to the original, because our
56	            //   `allocate()`, `grow()`, and `shrink()` implementations never returns a larger
57	            //   allocation than requested.
58	            // * Other conditions must be upheld by the caller, as per `Allocator::deallocate()`'s
59	            //   safety documentation.
60	            #[allow(clippy::disallowed_methods)] // we are in alloc_helper
61	            unsafe {
62	                alloc::alloc::dealloc(ptr.as_ptr(), layout)
63	            }
64	        }
65	    }
66	}
