69	#[must_use]
70	const fn without_provenance_mut<T>(addr: usize) -> *mut T {
71	    // An int-to-pointer transmute currently has exactly the intended semantics: it creates a
72	    // pointer without provenance. Note that this is *not* a stable guarantee about transmute
73	    // semantics, it relies on sysroot crates having special status.
74	    // SAFETY: every valid integer is also a valid pointer (as long as you don't dereference that
75	    // pointer).
76	    #[cfg(miri)]
77	    unsafe {
78	        core::mem::transmute(addr)
79	    }
80	    // Using transmute doesn't work with CHERI: https://github.com/kent-weak-memory/rust/blob/0c0ca909de877f889629057e1ddf139527446d75/library/core/src/ptr/mod.rs#L607
81	    #[cfg(not(miri))]
82	    {
83	        addr as *mut T
84	    }
85	}
